 48	  response?: QueryRangeResponse;
 49	  timeRange: TimeRange;
 50	}): {
 51	  data: Array<MetricsData> | undefined;
 52	  xDomain: Domain;
 53	  yDomain: Domain;
 54	} => {
 55	  if (!response) {
 56	    return { data: undefined, xDomain: [0, 1], yDomain: [0, 1] };
 57	  }
 58	
 59	  if (!isMatrixResult(response.data)) {
 60	    return { data: undefined, xDomain: [0, 1], yDomain: [0, 1] };
 61	  }
 62	
 63	  const numericTimeRangeValue = numericTimeRange(timeRange);
 64	
 65	  const values = response.data.result;
 66	  const xDomain: Domain = [numericTimeRangeValue.start, numericTimeRangeValue.end];
 67	  const yDomain: Domain = [Number.MAX_VALUE, Number.MIN_VALUE];
 68	
 69	  const data = values.map((value) => {
 70	    const seriesName = JSON.stringify(value.metric);
 71	    const seriesLabels = value.metric;
 72	
 73	    return {
 74	      name: seriesName,
 75	      labels: seriesLabels,
 76	      data: value.values.map((coordinate) => {
 77	        const time = parseInt(String(coordinate[0])) * 1000;
 78	
 79	        if (time < xDomain[0]) {
 80	          xDomain[0] = time;
 81	        }
 82	        if (time > xDomain[1]) {
 83	          xDomain[1] = time;
 84	        }
 85	
 86	        const y = parseFloat(String(coordinate[1]));
 87	
 88	        if (y < yDomain[0]) {
 89	          yDomain[0] = y;
 90	        }
 91	        if (y > yDomain[1]) {
 92	          yDomain[1] = y;
 93	        }
 94	
 95	        return { x: time, y, name: seriesName, labels: seriesLabels };
 96	      }),
 97	    };
 98	  });
 99	
100	  return { data, xDomain, yDomain };
101	};
102	
103	const CursorVoronoiContainer = createContainer('voronoi', 'cursor');
104	
105	export const LogsMetrics: React.FC<LogsMetricsProps> = ({
106	  logsData,
107	  isLoading,
108	  error,
109	  timeRange,
110	  height = GRAPH_HEIGHT,
111	  displayLegendTable = false,
112	  timezone,
113	}) => {
114	  const { t } = useTranslation('plugin__logging-view-plugin');
115	
116	  const [containerRef, width] = useRefWidth();
117	  const [timeRangeValue, setTimeRangeValue] = React.useState(numericTimeRange(timeRange));
118	  const { data, xDomain, yDomain } = React.useMemo(
119	    () => matrixToMetricsData({ response: logsData, timeRange: timeRange ?? defaultTimeRange() }),
120	    [logsData],
121	  );
122	
123	  React.useEffect(() => {
124	    setTimeRangeValue(numericTimeRange(timeRange));
125	  }, [timeRange]);
126	
127	  const toolTipData = React.useMemo(
128	    () =>
129	      data?.map((series) => ({
130	        childName: series.name,
131	        name: displayLegendTable ? undefined : series.name,
132	      })),
133	    [data],
134	  );
135	
136	  const { legendTableData, legendTableColumns } = React.useMemo(() => {
137	    const tableData: Array<{ childName: string; labels: Record<string, string> }> = [];
138	    const columns = new Set<string>();
139	
140	    if (data) {
141	      for (const metricsData of data) {
142	        tableData.push({
143	          childName: metricsData.name,
144	          labels: metricsData.labels,
145	        });
146	
147	        for (const label in metricsData.labels) {
148	          columns.add(label);
149	        }
150	      }
151	    }
152	
153	    return { legendTableData: tableData, legendTableColumns: Array.from(columns) };
154	  }, [data]);
155	
156	  const intervalValue = intervalFromTimeRange(timeRangeValue);
157	
158	  const dataIsEmpty = data ? data?.length === 0 : false;
159	
160	  return (
161	    <div ref={containerRef} data-test={TestIds.LogsMetrics}>
162	      {error ? (
163	        <CenteredContainer>
164	          <Alert
165	            variant="danger"
166	            isInline
167	            isPlain
168	            title={(error as Error).message || String(error)}
169	          />
170	        </CenteredContainer>
171	      ) : isLoading ? (
172	        <CenteredContainer>{t('Loading...')}</CenteredContainer>
173	      ) : dataIsEmpty ? (
174	        <CenteredContainer>
175	          <Alert variant="warning" isInline isPlain title={t('No datapoints found')} />
176	        </CenteredContainer>
177	      ) : data ? (
178	        <div>
179	          <Chart
180	            containerComponent={
181	              <CursorVoronoiContainer
182	                cursorDimension="x"
183	                activateData={false}
184	                labels={({ datum }: { datum: { y: number } }) => datum.y}
185	                labelComponent={
186	                  <ChartLegendTooltip
187	                    legendData={toolTipData}
188	                    title={(datum) =>
189	                      dateToFormat(
190	                        datum.x ?? 0,
191	                        getTimeFormatFromTimeRange(timeRangeValue),
192	                        timezone,
193	                      )
194	                    }
195	                  />
196	                }
197	                constrainToVisibleArea
198	                mouseFollowTooltips
199	                voronoiPadding={0}
200	              />
201	            }
202	            height={height}
203	            width={width}
204	            name="alert metrics"
205	            scale={{ x: 'time', y: 'linear' }}
206	            themeColor={ChartThemeColor.multiUnordered}
207	            padding={{
208	              bottom: 40,
209	              left: 100,
210	              right: 20,
211	              top: 10,
212	            }}
213	            domainPadding={{ x: [30, 25] }}
214	            domain={{ x: xDomain, y: yDomain }}
215	          >
216	            <ChartAxis
217	              tickCount={60}
218	              fixLabelOverlap
219	              tickFormat={(tick: number) =>
220	                dateToFormat(
221	                  tick,
222	                  intervalValue < 60 * 1000 ? DateFormat.TimeMed : DateFormat.TimeShort,
223	                  timezone,
224	                )
225	              }
226	            />
227	            <ChartAxis dependentAxis showGrid tickFormat={formatValue} />
228	            <ChartGroup>
229	              {data.map((series) => (
230	                <ChartLine name={series.name} key={series.name} data={series.data} />
231	              ))}
232	            </ChartGroup>
233	          </Chart>
234	          {displayLegendTable && (
235	            <InnerScrollContainer>
236	              <Table variant="compact" aria-label="alert metrics">
237	                <Thead>
238	                  <Tr>
239	                    <Th isStickyColumn stickyMinWidth="20px" style={{ width: '20px' }}></Th>
240	                    {legendTableColumns.map((column) => (
241	                      <Th modifier="nowrap" key={column}>
242	                        {column}
243	                      </Th>
244	                    ))}
245	                  </Tr>
246	                </Thead>
247	                <Tbody>
248	                  {legendTableData?.map((series, index) => (
249	                    <Tr key={series.childName}>
250	                      <Th isStickyColumn stickyMinWidth="20px" style={{ width: '20px' }}>
251	                        <div
252	                          className="lv-plugin__metrics-legent-table-color"
253	                          style={{ backgroundColor: colors?.[index] }}
254	                        />
255	                      </Th>
256	                      {legendTableColumns.map((column) => (
257	                        <Td key={`${column}-${index}`}>{series.labels[column]}</Td>
258	                      ))}
259	                    </Tr>
260	                  ))}
261	                </Tbody>
262	              </Table>
263	            </InnerScrollContainer>
264	          )}
265	        </div>
266	      ) : (
267	        <CenteredContainer>
268	          <Alert variant="danger" isInline isPlain title={t('Invalid data')} />
269	        </CenteredContainer>
270	      )}
271	    </div>
272	  );
273	};

